from typing import List
import sys
sys.setrecursionlimit(10000)

def solve(n: int, k: int) -> int:
    def popcount(x: int) -> int:
        return bin(x).count('1')

    def dfs(x: int, depth: int) -> int:
        if x == 1:
            return 1
        if depth >= k:
            return 0
        return dfs(popcount(x), depth + 1)

    count = 0
    for x in range(1, n + 1):
        if dfs(x, 0) == k:
            count += 1
    return count
